SELECT 
FROM users u

WHERE 1 = 1

    AND (u.email LIKE CONCAT('%', #{keyword}, '%') OR u.name LIKE CONCAT('%', #{keyword}, '%'))


    AND u.status = #{status}


    AND u.role = #{role}

ORDER BY u.created_at DESC
LIMIT #{limit}

SELECT 
FROM users u

WHERE u.id = #{id}

