FROM user_login_history
WHERE user_id = #{userId}
ORDER BY created_at DESC
LIMIT #{limit}

SELECT *
FROM user_status_history
WHERE user_id = #{userId}
ORDER BY created_at DESC
LIMIT #{limit}

